## 5. GraphQL 스키마 예시 (핵심 타입)

```graphql
# /graphql/src/main/resources/graphql/schema.graphqls

type User {
    id: ID!
    nickname: String!
    gender: String!
    profileImageUrl: String
    mannerScore: Float!
    isFollowing: Boolean!
    isOnline: Boolean!
}

type CallSession {
    id: ID!
    caller: User!
    receiver: User!
    status: String!
    durationSeconds: Int
    createdAt: String!
}

type Post {
    id: ID!
    user: User!
    content: String
    mediaList: [PostMedia!]!
    likeCount: Int!
    commentCount: Int!
    isLiked: Boolean!
    createdAt: String!
}

type ChatRoom {
    id: ID!
    partner: User!
    lastMessagePreview: String
    unreadCount: Int!
    lastMessageAt: String
}

extend type Query {
    me: User!
    userProfile(userId: ID!): User
    callHistory(limit: Int, offset: Int): [CallSession!]!
    feed(limit: Int, offset: Int): [Post!]!
    chatRooms: [ChatRoom!]!
    notifications(limit: Int, offset: Int): [Notification!]!
}

extend type Mutation {
    requestCall(receiverId: ID!): CallSession!
    createPost(input: CreatePostInput!): Post!
    likePost(postId: ID!): Boolean!
    sendMessage(input: SendMessageInput!): Boolean!
    followUser(targetUserId: ID!): Boolean!
}
```

